    final total = (week['total'] as num).toDouble();
    double maxV = 1;
    for (final d in days) {
      final t = (d['total'] as num).toDouble();
      if (t > maxV) maxV = t;
    }
    return Column(
      children: [
        Padding(
          padding: const EdgeInsets.fromLTRB(20, 6, 20, 8),
          child: Row(children: [
            const Text('Šios savaitės išlaidos', style: TextStyle(fontSize: 14.5, color: _muted, fontWeight: FontWeight.w500)),
