class _SparkPainter extends CustomPainter {
  _SparkPainter(this.pts);
  final List<double> pts;
  @override
  void paint(Canvas canvas, Size size) {
    if (pts.length < 2) return;
    final mn = pts.reduce((a, b) => a < b ? a : b);
    final mx = pts.reduce((a, b) => a > b ? a : b);
    final range = (mx - mn).abs() < 1e-6 ? 1.0 : (mx - mn);
    final path = Path();
    for (var i = 0; i < pts.length; i++) {
      final x = i / (pts.length - 1) * size.width;
      final y = size.height - (pts[i] - mn) / range * size.height;
      i == 0 ? path.moveTo(x, y) : path.lineTo(x, y);
    }
    canvas.drawPath(
      path,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 2
        ..strokeCap = StrokeCap.round
        ..strokeJoin = StrokeJoin.round
        ..color = _purple,
    );
  }

  @override
  bool shouldRepaint(_SparkPainter old) => false;
}

class _MiniRingPainter extends CustomPainter {
  @override
  void paint(Canvas canvas, Size size) {
    final c = size.center(Offset.zero);
    final r = size.width / 2 - 3;
    canvas.drawCircle(c, r, Paint()..style = PaintingStyle.stroke..strokeWidth = 5..color = Colors.white.withValues(alpha: 0.25));
    canvas.drawArc(
      Rect.fromCircle(center: c, radius: r),
      -1.5708,
      4.4,
      false,
      Paint()
        ..style = PaintingStyle.stroke
        ..strokeWidth = 5
        ..strokeCap = StrokeCap.round
        ..color = Colors.white,
    );
  }

  @override
  bool shouldRepaint(_MiniRingPainter old) => false;
}

