class _TxDetailScreen extends StatefulWidget {
  const _TxDetailScreen({required this.tx, required this.day, required this.all, required this.budgets});
  final Map<String, dynamic> tx;
  final Map<String, dynamic> day;
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> budgets;
  @override
  State<_TxDetailScreen> createState() => _TxDetailScreenState();
}

class _TxDetailScreenState extends State<_TxDetailScreen> {
  late String _cat = widget.tx['cat'] as String;
  late Color _catColor = _colOf(widget.tx['col'] as String?);
  late IconData _catIcon = _iconOf(widget.tx['ic'] as String?);
  late bool _isTransfer = widget.tx['col'] == 'transfer';

  Map<String, dynamic> get tx => widget.tx;
  double get amount => (tx['a'] as num).toDouble();
  bool get isPos => tx['pos'] == true;
  String get merchant => _shortNm(tx['nm'] as String);

  String get _dateFull {
    final d = DateTime.parse(widget.day['date'] as String);
    String two(int n) => n.toString().padLeft(2, '0');
    return '${widget.day['wd']}, ${two(d.day)}.${two(d.month)}.${d.year}';
  }

  List<Map<String, dynamic>> get _similar {
    final key = _brandKey(tx['nm'] as String);
    return widget.all.where((t) => t['mkey'] == key).toList();
  }

  double _catSpentThisMonth() {
    if (widget.all.isEmpty) return 0;
    final month = (widget.all.first['d'] as String).substring(0, 7);
    return widget.all
        .where((t) => t['cat'] == _cat && !(t['pos'] as bool) && (t['d'] as String).startsWith(month))
        .fold(0.0, (s, t) => s + (t['a'] as num).toDouble().abs());
  }

  void _toast(String m) => ScaffoldMessenger.of(context)
    ..hideCurrentSnackBar()
    ..showSnackBar(SnackBar(content: Text(m), duration: const Duration(milliseconds: 1500)));

  void _pickCategory() {
    showModalBottomSheet<Map<String, dynamic>>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(24))),
      builder: (_) => _SelectCategorySheet(current: _cat),
    ).then((res) {
      if (res != null) {
        setState(() {
          _cat = res['cat'] as String;
          _catColor = _secColor[res['c']] ?? _catColor;
          _catIcon = _secIcon[res['i']] ?? _catIcon;
        });
        _toast('Kategorija pakeista į „$_cat"');
      }
    });
  }

  void _reportIssue() {
    showModalBottomSheet<String>(
      context: context,
      backgroundColor: Colors.white,
      shape: const RoundedRectangleBorder(borderRadius: BorderRadius.vertical(top: Radius.circular(24))),
      builder: (_) => const _ReportIssueSheet(),
    ).then((res) {
      if (res != null) _toast('Ačiū! Pranešta: $res');
    });
  }

  @override
  Widget build(BuildContext context) {
    final similar = _similar;
    final budgetLimit = (widget.budgets[_cat] as num?)?.toDouble();
    return Scaffold(
      backgroundColor: _bg,
      body: SafeArea(
        bottom: false,
        child: Column(
          children: [
            Container(
              color: Colors.white,
              child: Column(children: [_topBar(), const SizedBox(height: 6), _hero(), const SizedBox(height: 18), _dateRow(), const SizedBox(height: 14)]),
            ),
            Expanded(
              child: ListView(
                padding: const EdgeInsets.only(top: 14, bottom: 30),
                children: [
                  _categoryCard(),
                  _detailsBox(),
                  _actions(),
                  if (budgetLimit != null) _budgetCard(budgetLimit),
                  _accountCard(),
                  if (similar.length > 1) _similarSection(similar),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _topBar() {
    return Padding(
      padding: const EdgeInsets.fromLTRB(6, 4, 10, 4),
      child: Row(
        children: [
          IconButton(onPressed: () => Navigator.pop(context), icon: const Icon(Icons.arrow_back_ios_new_rounded, size: 20, color: _ink)),
          Expanded(
            child: Text(_isTransfer ? 'Vidinis pervedimas' : 'Įprastas sandoris',
                style: const TextStyle(fontSize: 18, fontWeight: FontWeight.w700, color: _ink)),
          ),
          IconButton(onPressed: () => _toast('Ištrinti — ruošiama'), icon: const Icon(Icons.delete_outline_rounded, size: 22, color: _muted)),
          IconButton(onPressed: () => _toast('Pažymėta žvaigždute'), icon: const Icon(Icons.star_border_rounded, size: 24, color: _muted)),
          IconButton(onPressed: () => _toast('Redaguoti — ruošiama'), icon: const Icon(Icons.edit_outlined, size: 21, color: _purple)),
        ],
      ),
    );
  }

  Widget _hero() {
    return Column(
      children: [
        CategoryIcon(icon: _isTransfer ? Icons.swap_horiz_rounded : _catIcon, color: _isTransfer ? const Color(0xFF3E3B54) : _catColor, size: 76, circle: false),
        const SizedBox(height: 14),
        Text(merchant, style: const TextStyle(fontSize: 27, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
        const SizedBox(height: 4),
        Text(_eur(amount, signed: true), style: TextStyle(fontSize: 20, fontWeight: FontWeight.w700, color: isPos ? _good : _ink)),
      ],
    );
  }

  Widget _dateRow() {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 20),
      child: Row(
        children: [
          const Text('Data', style: TextStyle(fontSize: 15, color: _muted)),
          const Spacer(),
          Text(_dateFull, style: const TextStyle(fontSize: 15, fontWeight: FontWeight.w600, color: _ink)),
        ],
      ),
    );
  }

  Widget _categoryCard() {
    final pt = _ptype(tx);
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      child: AppCard(
        padding: EdgeInsets.zero,
        child: Row(
          children: [
            Expanded(
              child: Padding(
                padding: const EdgeInsets.fromLTRB(14, 12, 8, 12),
                child: Row(
                  children: [
                    CategoryIcon(icon: _catIcon, color: _catColor, size: 42),
                    const SizedBox(width: 12),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(_cat, style: const TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: _ink)),
                          const SizedBox(height: 2),
                          Row(children: [
                            const Flexible(child: Text('Kategorizuota AI', maxLines: 1, overflow: TextOverflow.ellipsis, style: TextStyle(fontSize: 12.5, color: _muted))),
                            const SizedBox(width: 6),
                            Container(
                              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 1),
                              decoration: BoxDecoration(color: _purpleSoft, borderRadius: BorderRadius.circular(5)),
                              child: Text(pt[0], style: const TextStyle(fontSize: 10, fontWeight: FontWeight.w700, color: _purple)),
                            ),
                          ]),
                        ],
                      ),
                    ),
                    Text(_eur(amount, signed: true), style: const TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink)),
                  ],
                ),
              ),
            ),
            InkWell(
              onTap: _pickCategory,
              child: Container(
                padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 26),
                decoration: const BoxDecoration(border: Border(left: BorderSide(color: DS.hairline))),
                child: const Icon(Icons.edit_outlined, size: 20, color: _purple),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Widget _detailsBox() {
    return Padding(
      padding: const EdgeInsets.fromLTRB(20, 0, 20, 14),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          const Text('Sandorio informacija', style: TextStyle(fontSize: 12.5, color: _muted, fontWeight: FontWeight.w600)),
          const SizedBox(height: 8),
          Container(
            width: double.infinity,
            padding: const EdgeInsets.all(14),
            decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(14), border: Border.all(color: DS.hairline)),
            child: Text('Prekybininkas: ${tx['nm']}', style: const TextStyle(fontSize: 14.5, color: _ink)),
          ),
        ],
      ),
    );
  }

  Widget _actions() {
    final chips = <List<dynamic>>[
      [Icons.edit_outlined, 'Redaguoti', () => _toast('Redaguoti — ruošiama')],
      [Icons.tag_rounded, 'Žyma', () => _toast('Žyma — ruošiama')],
      [Icons.repeat_rounded, 'Prie pasikartojančių', () => _toast('Pridėta prie pasikartojančių')],
      [Icons.swap_horiz_rounded, _isTransfer ? 'Į įprastą' : 'Į vidinį pervedimą', () => setState(() {
            _isTransfer = !_isTransfer;
            _toast(_isTransfer ? 'Konvertuota į vidinį pervedimą' : 'Konvertuota į įprastą');
          })],
      [Icons.flag_outlined, 'Pranešti klaidą', _reportIssue],
      [Icons.attach_file_rounded, 'Priedas', () => _toast('Priedas — ruošiama')],
    ];
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
      child: Wrap(
        spacing: 8,
        runSpacing: 8,
        children: [
          for (final c in chips)
            InkWell(
