// SELECT CATEGORY sheet — Vaultie taxonomy
// ══════════════════════════════════════════════════════════════════════════════
class _SelectCategorySheet extends StatefulWidget {
  const _SelectCategorySheet({required this.current});
  final String current;
  @override
  State<_SelectCategorySheet> createState() => _SelectCategorySheetState();
}

class _SelectCategorySheetState extends State<_SelectCategorySheet> {
  String _q = '';

  @override
  Widget build(BuildContext context) {
    return DraggableScrollableSheet(
      initialChildSize: 0.88,
      minChildSize: 0.5,
      maxChildSize: 0.95,
      expand: false,
      builder: (_, ctrl) => Column(
        children: [
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 14, 20, 6),
            child: Row(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                GestureDetector(onTap: () => Navigator.pop(context), child: const Padding(padding: EdgeInsets.only(right: 14, top: 4), child: Icon(Icons.close_rounded, size: 24, color: _ink))),
                const Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('SANDORIS', style: TextStyle(fontSize: 11, color: _muted, fontWeight: FontWeight.w700, letterSpacing: 0.8)),
                    Text('Pasirinkti kategoriją', style: TextStyle(fontSize: 24, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
                  ],
                ),
              ],
            ),
          ),
          Padding(
            padding: const EdgeInsets.fromLTRB(20, 8, 20, 8),
            child: TextField(
              onChanged: (v) => setState(() => _q = v.toLowerCase()),
              decoration: const InputDecoration(
                hintText: 'Ieškoti',
                suffixIcon: Icon(Icons.search_rounded, color: _muted),
                isDense: true,
                contentPadding: EdgeInsets.symmetric(horizontal: 4, vertical: 12),
                enabledBorder: UnderlineInputBorder(borderSide: BorderSide(color: DS.hairline)),
                focusedBorder: UnderlineInputBorder(borderSide: BorderSide(color: _purple)),
              ),
            ),
          ),
          Expanded(
            child: ListView(
              controller: ctrl,
              padding: const EdgeInsets.only(bottom: 24),
              children: [
                for (final sec in _taxonomy) ..._section(sec),
              ],
            ),
          ),
        ],
      ),
    );
  }

  List<Widget> _section(Map sec) {
    final subs = (sec['subs'] as List).cast<String>().where((s) => _q.isEmpty || s.toLowerCase().contains(_q)).toList();
    if (subs.isEmpty) return [];
    final color = _secColor[sec['c']] ?? _muted;
    return [
      Padding(
        padding: const EdgeInsets.fromLTRB(20, 14, 20, 6),
        child: Row(children: [
          CategoryIcon(icon: _secIcon[sec['i']] ?? Icons.circle, color: color, size: 30),
          const SizedBox(width: 10),
          Text(sec['sec'] as String, style: const TextStyle(fontSize: 15, fontWeight: FontWeight.w800, color: _ink)),
        ]),
      ),
      for (final sub in subs)
        InkWell(
          onTap: () => Navigator.pop(context, {'cat': sub, 'c': sec['c'], 'i': sec['i']}),
          child: Padding(
            padding: const EdgeInsets.fromLTRB(60, 11, 20, 11),
            child: Row(children: [
              Expanded(child: Text(sub, style: const TextStyle(fontSize: 15, color: _ink))),
              if (sub == widget.current) const Icon(Icons.check_rounded, size: 20, color: _purple),
            ]),
          ),
        ),
    ];
  }
}

