// MONTH IN REVIEW — full screen (opened from the dashboard review card)
// ══════════════════════════════════════════════════════════════════════════════
class _SecAgg {
  _SecAgg(this.label, this.colorKey);
  final String label;
  final String colorKey;
  double net = 0;
  Color get color => _secColor[colorKey] ?? _muted;
  IconData get icon => _secIcon[_secToIcon[label]] ?? Icons.circle;
}

class _MonthReviewScreen extends StatefulWidget {
  const _MonthReviewScreen({required this.all, required this.balance, required this.budgets, required this.month, required this.monthNom, required this.monthGen, required this.net});
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> balance;
  final Map<String, dynamic> budgets;
  final String month, monthNom, monthGen;
  final double net;
  @override
  State<_MonthReviewScreen> createState() => _MonthReviewScreenState();
}

class _MonthReviewScreenState extends State<_MonthReviewScreen> {
  List<Map<String, dynamic>> get _rows => widget.all.where((t) => (t['d'] as String).startsWith(widget.month)).toList();

  String get _prevMonth {
    final y = int.parse(widget.month.substring(0, 4));
    final m = int.parse(widget.month.substring(5, 7));
    return m == 1 ? '${y - 1}-12' : '$y-${(m - 1).toString().padLeft(2, '0')}';
  }

  String get _prevMonthNom => _monNom[(int.parse(widget.month.substring(5, 7)) + 10) % 12];

  bool _isIncome(String l) => l == 'Pajamos';
  bool _isTransfer(String l) => l == 'Pervedimai'; // 'Kita' = uncategorised spending, counts as expense

  List<_SecAgg> _sections() {
    final m = <String, _SecAgg>{};
    for (final t in _rows) {
      final label = t['sec'] as String;
      final a = m.putIfAbsent(label, () => _SecAgg(label, t['secc'] as String));
      a.net += (t['a'] as num).toDouble();
    }
    final list = m.values.toList()..sort((x, y) => y.net.abs().compareTo(x.net.abs()));
    return list;
  }

  @override
  Widget build(BuildContext context) {
    final secs = _sections();
    final expenseSecs = secs.where((s) => !_isIncome(s.label) && !_isTransfer(s.label) && s.net < 0).toList();
    final spent = expenseSecs.fold(0.0, (t, s) => t - s.net);
    final earned = secs.where((s) => _isIncome(s.label)).fold(0.0, (t, s) => t + (s.net > 0 ? s.net : 0));
    // savings = kept share of ALL money that came in (works across currencies; income alone
    // understates it because salary may arrive in another currency/account, e.g. NOK).
    final totalIn = _rows.where((t) => (t['a'] as num) > 0).fold(0.0, (s, t) => s + (t['a'] as num).toDouble());
    final savings = totalIn > 0 ? (widget.net / totalIn * 100).round().clamp(0, 100) : 0;

    return Scaffold(
      backgroundColor: _bg,
      body: Column(
        children: [
          _header(),
          Expanded(
            child: ListView(
              padding: const EdgeInsets.only(bottom: 30),
              children: [
                const SizedBox(height: 14),
                _filters(),
                _donuts(spent, earned, expenseSecs),
                _totalCard(),
                _statsRow(spent, earned, savings),
                _currencyNote(),
                _aiReport(spent, earned, expenseSecs),
                _balanceChart(),
                _calendar(),
                _savingsClub(savings),
                _categoryList(secs),
                _budgets(),
                _insights(),
                _avgDaily(expenseSecs),
                _merchants(),
                _largest(),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _header() {
    return Container(
      color: _purpleDeep,
      child: SafeArea(
        bottom: false,
        child: Padding(
          padding: const EdgeInsets.fromLTRB(6, 6, 14, 14),
          child: Row(
            children: [
              IconButton(onPressed: () => Navigator.pop(context), icon: const Icon(Icons.arrow_back_ios_new_rounded, size: 20, color: Colors.white)),
              Expanded(child: Text('${widget.monthGen} apžvalga', style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w700, color: Colors.white))),
              const Icon(Icons.help_outline_rounded, size: 24, color: Colors.white),
            ],
