  // ── helpers ──
  Map<String, double> _sectionSpend(String month) {
    final m = <String, double>{};
    for (final t in widget.all) {
      if (!(t['d'] as String).startsWith(month)) continue;
      final label = t['sec'] as String;
      if (_isIncome(label) || _isTransfer(label)) continue;
      final a = (t['a'] as num).toDouble();
      if (a < 0) m[label] = (m[label] ?? 0) - a;
    }
    return m;
  }

  Color _labelColor(String label) {
    final t = widget.all.firstWhere((t) => t['sec'] == label, orElse: () => const {});
    return _secColor[t['secc']] ?? _muted;
  }

  IconData _labelIcon(String label) => _secIcon[_secToIcon[label]] ?? Icons.circle;

  int get _daysInMonth {
    final y = int.parse(widget.month.substring(0, 4));
    final mo = int.parse(widget.month.substring(5, 7));
    return DateTime(y, mo + 1, 0).day;
  }

  Widget _sectionLabel(String s) => Padding(
        padding: const EdgeInsets.fromLTRB(20, 22, 20, 8),
        child: Text(s, style: const TextStyle(fontSize: 22, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.4)),
      );

  // ── CALENDAR heatmap ──
  Widget _calendar() {
    final y = int.parse(widget.month.substring(0, 4));
    final mo = int.parse(widget.month.substring(5, 7));
    final lead = DateTime(y, mo, 1).weekday - 1; // Mon=0
    final net = <int, double>{};
    final daySec = <int, Map<String, double>>{};
    for (final t in _rows) {
      final d = int.parse((t['d'] as String).substring(8, 10));
      final a = (t['a'] as num).toDouble();
      net[d] = (net[d] ?? 0) + a;
      final label = t['sec'] as String;
      if (!_isIncome(label) && !_isTransfer(label) && a < 0) {
        final sm = daySec.putIfAbsent(d, () => {});
        sm[t['secc'] as String] = (sm[t['secc'] as String] ?? 0) - a;
      }
    }
    Color? dom(int d) {
      final sm = daySec[d];
      if (sm == null || sm.isEmpty) return null;
      return _secColor[sm.entries.reduce((a, b) => a.value >= b.value ? a : b).key];
    }
    const wd = ['Pr', 'An', 'Tr', 'Kt', 'Pn', 'Št', 'Sk'];
    final cells = <Widget>[];
    for (var i = 0; i < lead; i++) {
      cells.add(const SizedBox());
    }
    for (var d = 1; d <= _daysInMonth; d++) {
      final n = net[d];
      final c = (n != null && n > 500) ? _secColor['amber'] : dom(d);
      cells.add(_calCell(d, n, c));
    }
    return Container(
      margin: const EdgeInsets.fromLTRB(16, 0, 16, 14),
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(16), border: Border.all(color: DS.hairline)),
      child: Column(
        children: [
          Row(children: [for (final w in wd) Expanded(child: Center(child: Text(w, style: const TextStyle(fontSize: 12, color: _muted, fontWeight: FontWeight.w600))))]),
          const SizedBox(height: 6),
          GridView.count(
            crossAxisCount: 7,
            shrinkWrap: true,
            physics: const NeverScrollableScrollPhysics(),
            childAspectRatio: 0.82,
            children: cells,
          ),
        ],
      ),
    );
  }

  Widget _calCell(int d, double? n, Color? c) {
    return Container(
      margin: const EdgeInsets.all(2),
      decoration: BoxDecoration(
        color: c?.withValues(alpha: 0.10) ?? Colors.transparent,
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: c?.withValues(alpha: 0.55) ?? DS.hairline, width: 1.1),
      ),
      child: Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('$d', style: const TextStyle(fontSize: 12, fontWeight: FontWeight.w700, color: _ink)),
          if (n != null) Text('${n.round()}€', style: TextStyle(fontSize: 9.5, fontWeight: FontWeight.w600, color: n >= 0 ? _good : _muted)),
        ],
      ),
    );
  }

  // ── BUDGETS ──
  Widget _budgets() {
    final b = widget.budgets;
    final spentByCat = <String, double>{};
    for (final t in _rows) {
      final a = (t['a'] as num).toDouble();
      if (a < 0) spentByCat[t['cat'] as String] = (spentByCat[t['cat'] as String] ?? 0) - a;
    }
    final cats = b.keys.toList();
    final totalBudget = cats.fold(0.0, (s, c) => s + (b[c] as num).toDouble());
    final totalSpent = cats.fold(0.0, (s, c) => s + (spentByCat[c] ?? 0));
    final under = totalBudget - totalSpent;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _sectionLabel('Biudžetai'),
        Container(
          margin: const EdgeInsets.fromLTRB(16, 0, 16, 12),
          padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(16),
            gradient: const LinearGradient(begin: Alignment.topLeft, end: Alignment.bottomRight, colors: [_purpleDeep, _purple]),
          ),
          child: Text(
