  // ── MERCHANTS ──
  Widget _merchants() {
    final count = _rows.map((t) => t['mkey']).toSet().length;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _sectionLabel('Prekybininkai'),
