  }

  // ── LARGEST EXPENSES ──
  Widget _largest() {
    final exp = _rows.where((t) => (t['a'] as num) < 0).toList()..sort((a, b) => (a['a'] as num).compareTo(b['a'] as num));
    final top = exp.take(5).toList();
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        _sectionLabel('Didžiausios išlaidos'),
        Padding(
          padding: const EdgeInsets.fromLTRB(16, 0, 16, 0),
          child: AppCard(
            child: Column(children: [
              for (var i = 0; i < top.length; i++) ...[
                Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 12),
                  child: Row(children: [
                    CategoryIcon(icon: _iconOf(top[i]['ic'] as String?), color: _colOf(top[i]['col'] as String?), size: 40, circle: false),
                    const SizedBox(width: 12),
                    Expanded(
                      child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
                        Text(_shortNm(top[i]['nm'] as String), style: const TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink)),
                        const SizedBox(height: 2),
                        Text('${top[i]['md']}; ${top[i]['cat']}', maxLines: 1, overflow: TextOverflow.ellipsis, style: const TextStyle(fontSize: 12.5, color: _muted)),
                      ]),
                    ),
                    const SizedBox(width: 8),
                    Text(_eur((top[i]['a'] as num).toDouble(), signed: true),
                        style: const TextStyle(fontSize: 15.5, fontWeight: FontWeight.w700, color: _ink, fontFeatures: [FontFeature.tabularFigures()])),
                  ]),
                ),
                if (i != top.length - 1) const RowDivider(indent: 66),
              ],
            ]),
          ),
        ),
      ],
    );
  }
}

class _RingProgressPainter extends CustomPainter {
  _RingProgressPainter(this.ratio);
  final double ratio;
  @override
  void paint(Canvas canvas, Size size) {
    final c = size.center(Offset.zero);
    final r = size.width / 2 - 4;
    canvas.drawCircle(c, r, Paint()..style = PaintingStyle.stroke..strokeWidth = 6..color = const Color(0xFFE7F0E8));
    canvas.drawArc(Rect.fromCircle(center: c, radius: r), -math.pi / 2, 2 * math.pi * ratio.clamp(0.0, 1.0), false,
        Paint()..style = PaintingStyle.stroke..strokeWidth = 6..strokeCap = StrokeCap.round..color = _good);
  }

  @override
  bool shouldRepaint(_RingProgressPainter old) => old.ratio != ratio;
}

class _DonutPainter extends CustomPainter {
  _DonutPainter(this.segments);
  final List<List<dynamic>> segments; // [value(double), color(Color)]
  static const double stroke = 15;
  @override
  void paint(Canvas canvas, Size size) {
    final rect = Rect.fromCircle(center: size.center(Offset.zero), radius: (math.min(size.width, size.height) - stroke) / 2);
    final total = segments.fold(0.0, (t, s) => t + (s[0] as double).abs());
    canvas.drawArc(rect, 0, 2 * math.pi, false, Paint()..style = PaintingStyle.stroke..strokeWidth = stroke..color = DS.track);
    if (total <= 0) return;
    if (segments.length == 1) {
      canvas.drawArc(rect, -math.pi / 2, 2 * math.pi, false,
          Paint()..style = PaintingStyle.stroke..strokeWidth = stroke..color = segments[0][1] as Color..strokeCap = StrokeCap.round);
      return;
    }
    var start = -math.pi / 2;
    const gap = 0.06;
    for (final s in segments) {
      final frac = (s[0] as double).abs() / total;
      final sweep = 2 * math.pi * frac - gap;
      if (sweep > 0) {
        canvas.drawArc(rect, start + gap / 2, sweep, false,
            Paint()..style = PaintingStyle.stroke..strokeWidth = stroke..color = s[1] as Color..strokeCap = StrokeCap.round);
      }
      start += 2 * math.pi * frac;
    }
  }

  @override
  bool shouldRepaint(_DonutPainter old) => true;
}

