// CATEGORY DETAIL — colored section screen with subcategory breakdown
// ══════════════════════════════════════════════════════════════════════════════
class _CategoryDetailScreen extends StatelessWidget {
  const _CategoryDetailScreen({required this.section, required this.rows, required this.monthName});
  final _SecAgg section;
  final List<Map<String, dynamic>> rows;
  final String monthName;

  @override
  Widget build(BuildContext context) {
    // group by subcategory (cat)
    final subs = <String, List<dynamic>>{}; // cat -> [sum, iconKey]
    for (final t in rows) {
      final c = t['cat'] as String;
      final e = subs.putIfAbsent(c, () => [0.0, t['ic']]);
      e[0] = (e[0] as double) + (t['a'] as num).toDouble();
    }
    final subList = subs.entries.toList()..sort((a, b) => (a.value[0] as double).compareTo(b.value[0] as double));
    final neg = rows.where((t) => (t['a'] as num) < 0).fold(0.0, (s, t) => s + (t['a'] as num).toDouble());
    final pos = rows.where((t) => (t['a'] as num) > 0).fold(0.0, (s, t) => s + (t['a'] as num).toDouble());

    return Scaffold(
      backgroundColor: _bg,
      body: Column(
        children: [
          // coloured header
          Container(
            color: section.color,
            child: SafeArea(
              bottom: false,
              child: Column(
                children: [
                  Padding(
                    padding: const EdgeInsets.fromLTRB(6, 6, 14, 0),
                    child: Row(children: [
                      IconButton(onPressed: () => Navigator.pop(context), icon: const Icon(Icons.arrow_back_ios_new_rounded, size: 20, color: Colors.white)),
                      Expanded(child: Text(section.label, style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w700, color: Colors.white))),
                      const Icon(Icons.search_rounded, size: 24, color: Colors.white),
                    ]),
                  ),
                  const SizedBox(height: 8),
                  Icon(section.icon, size: 64, color: Colors.white),
                  const SizedBox(height: 10),
                  Text(section.label, style: const TextStyle(fontSize: 26, fontWeight: FontWeight.w800, color: Colors.white)),
                  const SizedBox(height: 2),
                  Text(_eur(section.net, signed: true), style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w700, color: Colors.white)),
                  const SizedBox(height: 20),
                ],
              ),
            ),
          ),
          Expanded(
            child: ListView(
              padding: const EdgeInsets.fromLTRB(16, 16, 16, 30),
              children: [
                const Padding(
                  padding: EdgeInsets.fromLTRB(4, 0, 4, 8),
                  child: Row(children: [Text('Kategorija', style: TextStyle(fontSize: 13, color: _muted)), Spacer(), Text('Suma', style: TextStyle(fontSize: 13, color: _muted))]),
                ),
                AppCard(
                  child: Column(children: [
                    for (var i = 0; i < subList.length; i++) ...[
                      Padding(
                        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 13),
                        child: Row(children: [
                          CategoryIcon(icon: _iconOf(subList[i].value[1] as String?), color: section.color, size: 40),
                          const SizedBox(width: 13),
                          Expanded(child: Text(subList[i].key, style: const TextStyle(fontSize: 16, fontWeight: FontWeight.w600, color: _ink))),
                          Text(_eur(subList[i].value[0] as double, signed: true),
                              style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700, color: (subList[i].value[0] as double) >= 0 ? _good : _ink, fontFeatures: const [FontFeature.tabularFigures()])),
                        ]),
                      ),
                      if (i != subList.length - 1) const RowDivider(indent: 66),
                    ],
                    InkWell(
                      onTap: () {},
                      child: const Padding(
                        padding: EdgeInsets.symmetric(horizontal: 14, vertical: 14),
                        child: Row(children: [
                          Icon(Icons.create_new_folder_outlined, size: 22, color: _purple),
                          SizedBox(width: 14),
                          Text('Redaguoti / pridėti kategorijas', style: TextStyle(fontSize: 15, fontWeight: FontWeight.w600, color: _purple)),
                        ]),
                      ),
                    ),
                  ]),
                ),
                const SizedBox(height: 14),
                Container(
                  padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 14),
                  decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(14), border: Border.all(color: DS.hairline)),
                  child: Row(children: [
                    CategoryIcon(icon: section.icon, color: section.color, size: 26),
                    const SizedBox(width: 8),
                    Text('Neigiama: ${_eur(neg)}', style: const TextStyle(fontSize: 14, fontWeight: FontWeight.w600, color: _ink)),
                    const Spacer(),
                    Text('Teigiama: ${_eur(pos)}', style: const TextStyle(fontSize: 14, fontWeight: FontWeight.w600, color: _ink)),
                  ]),
                ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

