// OVERVIEW TAB — analytics for the selected period (defaults to current month)
// ══════════════════════════════════════════════════════════════════════════════
class _OverviewTab extends StatefulWidget {
  const _OverviewTab({required this.all, required this.balance, required this.budgets});
  final List<Map<String, dynamic>> all;
  final Map<String, dynamic> balance;
  final Map<String, dynamic> budgets;
  @override
  State<_OverviewTab> createState() => _OverviewTabState();
}

class _OverviewTabState extends State<_OverviewTab> {
  bool _merchantsOpen = false;

  List<String> get _monthKeys {
    final s = widget.all.map((t) => (t['d'] as String).substring(0, 7)).toSet().toList()..sort();
    return s; // ascending
  }

  String get _curKey => _monthKeys.last;
  int get _curMon => int.parse(_curKey.substring(5, 7));
  List<Map<String, dynamic>> _rowsOf(String mk) => widget.all.where((t) => (t['d'] as String).startsWith(mk)).toList();
  List<Map<String, dynamic>> get _rows => _rowsOf(_curKey);

  bool _isIncome(String l) => l == 'Pajamos';
  bool _isTransfer(String l) => l == 'Pervedimai';

  List<_SecAgg> _sections(List<Map<String, dynamic>> rows) {
    final m = <String, _SecAgg>{};
    for (final t in rows) {
      final a = m.putIfAbsent(t['sec'] as String, () => _SecAgg(t['sec'] as String, t['secc'] as String));
      a.net += (t['a'] as num).toDouble();
    }
    return m.values.toList()..sort((x, y) => y.net.abs().compareTo(x.net.abs()));
  }

  double _spentOf(List<Map<String, dynamic>> rows) => _sections(rows)
      .where((s) => !_isIncome(s.label) && !_isTransfer(s.label) && s.net < 0)
      .fold(0.0, (t, s) => t - s.net);
  double _earnedOf(List<Map<String, dynamic>> rows) =>
      rows.where((t) => t['sec'] == 'Pajamos' && (t['a'] as num) > 0).fold(0.0, (s, t) => s + (t['a'] as num).toDouble());
  double _netOf(List<Map<String, dynamic>> rows) => rows.fold(0.0, (s, t) => s + (t['a'] as num).toDouble());
  int _savingsOf(List<Map<String, dynamic>> rows) {
    final inn = rows.where((t) => (t['a'] as num) > 0).fold(0.0, (s, t) => s + (t['a'] as num).toDouble());
    return inn > 0 ? (_netOf(rows) / inn * 100).round().clamp(0, 100) : 0;
  }

  @override
  Widget build(BuildContext context) {
    final secs = _sections(_rows);
    final expenseSecs = secs.where((s) => !_isIncome(s.label) && !_isTransfer(s.label) && s.net < 0).toList();
    final spent = _spentOf(_rows);
    final earned = _earnedOf(_rows);
    final net = _netOf(_rows);
    final savings = _savingsOf(_rows);
    final prevKey = _monthKeys.length > 1 ? _monthKeys[_monthKeys.length - 2] : null;
    final prevSavings = prevKey != null ? _savingsOf(_rowsOf(prevKey)) : 0;

    return SafeArea(
      bottom: false,
      child: ListView(
        padding: const EdgeInsets.only(bottom: 28),
        children: [
          _header(),
          _filters(),
          _donuts(spent, earned, expenseSecs),
          _totalCard(net),
          _savingsCard(savings, prevSavings, prevKey),
          _categoryList(secs),
          _tags(),
          _analyticsLabel(),
          _calendar(),
          _merchants(),
          _last6(),
          _avgDaily(expenseSecs),
        ],
      ),
    );
  }

  Widget _header() => const Padding(
        padding: EdgeInsets.fromLTRB(16, 6, 16, 12),
        child: Row(children: [
          Text('Overview', style: TextStyle(fontSize: 30, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.5)),
          Spacer(),
          Icon(Icons.visibility_outlined, size: 25, color: _ink),
          SizedBox(width: 14),
          Icon(Icons.search_rounded, size: 25, color: _ink),
        ]),
      );

  Widget _filters() => const Padding(
        padding: EdgeInsets.fromLTRB(16, 0, 16, 10),
        child: Row(children: [
          _Chip(icon: Icons.calendar_today_rounded, label: 'Šis mėnuo'),
          SizedBox(width: 9),
          _Chip(icon: Icons.tune_rounded, label: 'Filtras'),
        ]),
      );

  Widget _donuts(double spent, double earned, List<_SecAgg> exp) {
    return Padding(
      padding: const EdgeInsets.fromLTRB(16, 8, 16, 4),
      child: Row(children: [
        Expanded(child: _donut(spent, [for (final s in exp) [-s.net, s.color]], '−', 'Išleista')),
        Expanded(child: _donut(earned, earned > 0 ? [[earned, _secColor['amber']!]] : [], '+', 'Uždirbta')),
      ]),
    );
  }

  Widget _donut(double v, List<List<dynamic>> segs, String sign, String label) => AspectRatio(
        aspectRatio: 1,
        child: Stack(alignment: Alignment.center, children: [
          CustomPaint(size: Size.infinite, painter: _DonutPainter(segs)),
          Column(mainAxisSize: MainAxisSize.min, children: [
            Text(sign, style: const TextStyle(fontSize: 20, color: _muted, height: 1)),
            const SizedBox(height: 2),
            Text('${v.round()} €', style: const TextStyle(fontSize: 24, fontWeight: FontWeight.w800, color: _ink, letterSpacing: -0.5)),
            Text(label, style: const TextStyle(fontSize: 13, color: _muted)),
          ]),
        ]),
      );

  Widget _totalCard(double net) => Container(
        margin: const EdgeInsets.fromLTRB(16, 10, 16, 10),
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 15),
        decoration: BoxDecoration(color: Colors.white, borderRadius: BorderRadius.circular(14), border: Border.all(color: DS.hairline)),
        child: Row(children: [
          Text('${_monGen[_curMon - 1]} suma', style: const TextStyle(fontSize: 17, fontWeight: FontWeight.w700, color: _ink)),
          const Spacer(),
          Text(_eur(net, signed: true), style: TextStyle(fontSize: 17, fontWeight: FontWeight.w800, color: net >= 0 ? _good : _ink)),
        ]),
      );

  Widget _savingsCard(int savings, int prevSavings, String? prevKey) => GestureDetector(
        onTap: () => Navigator.of(context).push(MaterialPageRoute(
          builder: (_) => _SavingsRateScreen(all: widget.all, monthKeys: _monthKeys, savingsOf: _savingsOf, rowsOf: _rowsOf),
        )),
        child: Container(
          margin: const EdgeInsets.fromLTRB(16, 0, 16, 14),
